// PERSISTENT SCORE STORAGE (JSONBin.io)
// ============================================================
// ※ JSONBin.io 무료 서비스를 사용합니다.
//   아래 두 값을 JSONBin에서 발급받은 값으로 교체하세요:
//   JSONBIN_BIN_ID  : Bin ID (숫자+문자 혼합)
//   JSONBIN_API_KEY : API Key ($2b$10$... 형태)
// ─────────────────────────────────────────────────────────────
const JSONBIN_BIN_ID  = "6a2a60ecda38895dfeaba5ce";
const JSONBIN_API_KEY = "$2a$10$m7G5pXX3trEYFVwemmNXYun0/A8blUKscu24twOEnkvCowx3BjfUm";
const JSONBIN_URL = `https://api.jsonbin.io/v3/b/${JSONBIN_BIN_ID}`;

const DEFAULT_RANKINGS = [];
const DEFAULT_DEPT_STATS = [
    {name:"본사",total:0,members:0},{name:"화폐본부",total:0,members:0},
    {name:"기술연구원",total:0,members:0},{name:"ID본부",total:0,members:0},{name:"제지본부",total:0,members:0}
];

let _scoreCache = null;

async function loadScoreData() {
    if (_scoreCache) return _scoreCache;
    try {
        const res = await fetch(JSONBIN_URL + "/latest", {
            headers: { "X-Master-Key": JSONBIN_API_KEY }
        });
        if (!res.ok) throw new Error("fetch failed");
        const json = await res.json();
        const data = json.record;
        _scoreCache = data;
        return data;
    } catch(e) {
        console.warn("JSONBin 점수 불러오기 실패, 기본값 사용:", e);
        return { rankings: JSON.parse(JSON.stringify(DEFAULT_RANKINGS)), deptStats: JSON.parse(JSON.stringify(DEFAULT_DEPT_STATS)) };
    }
}

async function saveScoreData(data) {
    _scoreCache = data;
    try {
        const res = await fetch(JSONBIN_URL, {
            method: "PUT",
            headers: {
                "Content-Type": "application/json",
                "X-Master-Key": JSONBIN_API_KEY
            },
            body: JSON.stringify(data)
        });
        if (res.ok) {
            console.log("✅ JSONBin 점수 저장 성공");
        } else {
            console.warn("JSONBin 저장 실패:", res.status);
        }
    } catch(e) {
        console.warn("JSONBin 저장 오류 (세션 메모리 유지):", e);
    }
}

function loadRankings() { return JSON.parse(JSON.stringify(DEFAULT_RANKINGS)); }
function saveRankings(data) { /* async 버전으로 대체됨 */ }
function loadDeptStats() { return JSON.parse(JSON.stringify(DEFAULT_DEPT_STATS)); }
function saveDeptStats(data) { /* async 버전으로 대체됨 */ }

let RANKINGS = JSON.parse(JSON.stringify(DEFAULT_RANKINGS));
let DEPT_STATS = JSON.parse(JSON.stringify(DEFAULT_DEPT_STATS));

// 비동기로 원격 데이터 로드
const FAKE_NAMES = ["서영훈","정은교","이보라","이규화","박찬혁"];
(async function() {
    const data = await loadScoreData();
    if (data.rankings) {
        // 구 가상 데이터만 있을 경우 빈 배열로 처리
        const realEntries = data.rankings.filter(r => !FAKE_NAMES.includes(r.name));
        RANKINGS = realEntries.length > 0 ? data.rankings : [];
    }
    if (data.deptStats) DEPT_STATS = data.deptStats;
})();

// ============================================================
// CHARACTER IMAGE LOADING
// ============================================================
function drawPortraits() {
    ["hunmin","sunsik","daim"].forEach(id => {
        const c = document.getElementById("portrait-" + id);
        if (!c) return;
        // 고화질: canvas 실제 크기를 2배로 설정하고 CSS로 원래 크기 유지
        const dpr = window.devicePixelRatio || 2;
        c.width = 64 * dpr;
        c.height = 64 * dpr;
        c.style.width = "64px";
        c.style.height = "64px";
        const x = c.getContext("2d");
        x.scale(dpr, dpr);
        x.imageSmoothingEnabled = true;
        x.imageSmoothingQuality = "high";
        const img = CHAR_IMGS[id];
        x.clearRect(0,0,64,64);
        if (img && img.complete && img.naturalWidth > 0) {
            // 첨부 캐릭터 이미지 전체를 카드 안에 자연스럽게 표시
            const aspect = img.naturalWidth / img.naturalHeight;
            let dw = 58, dh = 58;
            if (aspect > 1) dh = dw / aspect; else dw = dh * aspect;
            x.drawImage(img, (64-dw)/2, 3, dw, dh);
        } else {
            x.fillStyle = "#0e2a4a";
            x.beginPath(); x.arc(32,32,30,0,Math.PI*2); x.fill();
            x.fillStyle = "#38bdf8"; x.font = "bold 9px sans-serif"; x.textAlign = "center";
            x.fillText(id==="hunmin"?"훈민":id==="sunsik"?"순식":"다임", 32, 36);
        }
    });
}

function drawHUDPortrait(charId) {
    const c = document.getElementById("hud-portrait");
    if (!c) return;
    const dpr = window.devicePixelRatio || 2;
    c.width = 36 * dpr;
    c.height = 36 * dpr;
    c.style.width = "36px";
    c.style.height = "36px";
    const x = c.getContext("2d");
    x.scale(dpr, dpr);
    x.imageSmoothingEnabled = true;
    x.imageSmoothingQuality = "high";
    const img = CHAR_IMGS[charId];
    x.clearRect(0,0,36,36);
    if (img && img.complete && img.naturalWidth > 0) {
        const aspect = img.naturalWidth / img.naturalHeight;
        let dw = 34, dh = 34;
        if (aspect > 1) dh = dw / aspect; else dw = dh * aspect;
        x.drawImage(img, (36-dw)/2, 1, dw, dh);
    }
}

// ============================================================
// BGM (배경 음악)
// ============================================================
let bgmAudio = null;
let bgmPlaying = false;

function initBGM() {
    if (bgmAudio) return;
    bgmAudio = new Audio("data:audio/mp4;base64,");
    bgmAudio.loop = true;
    bgmAudio.volume = 0.45;
}

function playBGM() {
    initBGM();
    if (!bgmPlaying) {
        bgmAudio.currentTime = 0;
        bgmAudio.play().catch(function(){});
        bgmPlaying = true;
    }
}

function stopBGM() {
    if (bgmAudio && bgmPlaying) {
        bgmAudio.pause();
        bgmAudio.currentTime = 0;
        bgmPlaying = false;
    }
}

function pauseBGM() {
    if (bgmAudio && bgmPlaying) {
        bgmAudio.pause();
        bgmPlaying = false;
    }
}

// ============================================================
// AUDIO ENGINE
// ============================================================
let audioCtx = null;
function initAudio() {
    if (audioCtx) return;
    try {
        audioCtx = new (window.AudioContext || window.webkitAudioContext)();
    } catch(e) {}
}
function unlockAudio() {
    initAudio();
    if (audioCtx && audioCtx.state === "suspended") audioCtx.resume();
    initBGM(); // BGM 미리 초기화 (autoplay policy 대응)
}
window.addEventListener("touchstart", unlockAudio, {once:true});
window.addEventListener("click", unlockAudio, {once:true});

function playSound(type) {
    if (!audioCtx || audioCtx.state === "suspended") return;
    try {
        const osc = audioCtx.createOscillator();
        const gain = audioCtx.createGain();
        osc.connect(gain); gain.connect(audioCtx.destination);
        const now = audioCtx.currentTime;
        if (type === "jump") {
            osc.type = "triangle";
            osc.frequency.setValueAtTime(150, now);
            osc.frequency.exponentialRampToValueAtTime(700, now + 0.12);
            gain.gain.setValueAtTime(0.1, now);
            gain.gain.linearRampToValueAtTime(0.01, now + 0.12);
            osc.start(now); osc.stop(now + 0.12);
        } else if (type === "collect") {
            osc.type = "sine";
            osc.frequency.setValueAtTime(600, now);
            osc.frequency.setValueAtTime(1000, now + 0.07);
            gain.gain.setValueAtTime(0.07, now);
            gain.gain.linearRampToValueAtTime(0.01, now + 0.18);
            osc.start(now); osc.stop(now + 0.18);
        } else if (type === "skill") {
            osc.type = "sawtooth";
            osc.frequency.setValueAtTime(250, now);
            osc.frequency.linearRampToValueAtTime(1100, now + 0.45);
            gain.gain.setValueAtTime(0.07, now);
            gain.gain.exponentialRampToValueAtTime(0.001, now + 0.5);
            osc.start(now); osc.stop(now + 0.5);
        } else if (type === "crash") {
            osc.type = "sawtooth";
            osc.frequency.setValueAtTime(100, now);
            osc.frequency.linearRampToValueAtTime(20, now + 0.3);
            gain.gain.setValueAtTime(0.2, now);
            gain.gain.linearRampToValueAtTime(0.01, now + 0.35);
            osc.start(now); osc.stop(now + 0.35);
        }
    } catch(e) {}
}

