function showScreen(id) {
    ["menu","game","leaderboard","encyclopedia","gameover"].forEach(s => {
        document.getElementById("screen-" + s).classList.toggle("hidden", s !== id);
    });
    if (id === "leaderboard") { renderRankings(); renderDepts(); }
    if (id === "encyclopedia") renderEncyclopedia();
}

// ============================================================
// CHARACTER SELECTION
// ============================================================
function selectCharacter(id, options = {}) {
    if (!VALID_CHARACTER_IDS.includes(id)) id = "hunmin";
    selectedChar = id;
    ["hunmin","sunsik","daim"].forEach(c => {
        const btn = document.getElementById("char-btn-" + c);
        if (c === id) {
            btn.className = "touch-manipulation flex flex-col items-center p-3 bg-[#081835]/80 border-2 border-sky-500 rounded-2xl transition-all active:scale-95 text-center";
        } else {
            btn.className = "touch-manipulation flex flex-col items-center p-3 bg-slate-950 border-2 border-slate-800 rounded-2xl transition-all active:scale-95 text-center";
        }
    });
    if (!options.skipSave) saveUserSettingsCache();
}

