// ============================================================
function getUserSettingsCache() {
    try {
        const raw = localStorage.getItem(USER_SETTINGS_CACHE_KEY);
        return raw ? JSON.parse(raw) : {};
    } catch (e) {
        console.warn("사용자 설정 캐시 읽기 실패:", e);
        return {};
    }
}

function saveUserSettingsCache() {
    try {
        const nameEl = document.getElementById("input-name");
        const deptEl = document.getElementById("select-dept");
        const payload = {
            name: (nameEl?.value || "").trim(),
            dept: deptEl?.value || "본사",
            character: VALID_CHARACTER_IDS.includes(selectedChar) ? selectedChar : "hunmin"
        };
        localStorage.setItem(USER_SETTINGS_CACHE_KEY, JSON.stringify(payload));
    } catch (e) {
        console.warn("사용자 설정 캐시 저장 실패:", e);
    }
}

function applyUserSettingsCache() {
    const cache = getUserSettingsCache();
    const nameEl = document.getElementById("input-name");
    const deptEl = document.getElementById("select-dept");

    if (nameEl && typeof cache.name === "string" && cache.name.trim()) {
        nameEl.value = cache.name.trim();
    }
    if (deptEl && typeof cache.dept === "string") {
        const exists = Array.from(deptEl.options).some(opt => opt.value === cache.dept || opt.textContent === cache.dept);
        if (exists) deptEl.value = cache.dept;
    }

    selectCharacter(VALID_CHARACTER_IDS.includes(cache.character) ? cache.character : selectedChar, { skipSave: true });
}

function bindUserSettingsCacheEvents() {
    const nameEl = document.getElementById("input-name");
    const deptEl = document.getElementById("select-dept");
    nameEl?.addEventListener("input", saveUserSettingsCache);
    nameEl?.addEventListener("change", saveUserSettingsCache);
    deptEl?.addEventListener("change", saveUserSettingsCache);
}

// ============================================================
// GAME START / RESET
// ============================================================
function startGame() {
    if (isPlaying) return;
    const name = (document.getElementById("input-name").value || "조조달").trim();
    const dept = document.getElementById("select-dept").value;
    saveUserSettingsCache();
    document.getElementById("hud-name").textContent = name;
    document.getElementById("hud-dept").textContent = dept;
    document.getElementById("reg-info").textContent = name + " (" + dept + ")";

    gameScore = 0; accumulatedScore = 0; uniqueCollected.clear(); totalCollected = 0;
    itemCounts = {}; PUBLIC_PURCHASES.forEach(p => itemCounts[p.id] = 0);
    skillCharge = 0; isSkillActive = false; skillTimer = 0;
    gameSpeed = 2.6; distRun = 0; frame = 0;
    currentStage = 1; stageClearTimer = 0;
    obstacles = []; items = []; particles = [];
    playerLane = 1; isPaused = false; revivalUsed = false;
    comboCount = 0; comboTimer = 0; comboMultiplier = 1; comboHideTimer = 0;
    pbNotified = false;
    missionStats = {hurdlePassed:0, itemsCollected:0, maxCombo:0, stagesCleared:0, stage1Clear:0, bombJumped:0};

    // 일일 미션 생성 (날짜 기반 시드 → 매일 동일 3개)
    initDailyMissions();

    showScreen("game");
    resizeCanvas();

    scenery = [];
    for (let i = 0; i < 10; i++) {
        scenery.push({
            x: Math.random() < 0.5 ? 15 + Math.random()*20 : CW - (35 + Math.random()*20),
            y: (CH / 10) * i,
            type: ["tree","block","cloud"][Math.floor(Math.random()*3)],
            sc: 0.8 + Math.random()*0.5
        });
    }

    drawHUDPortrait(selectedChar);
    resetSkillBtn();
    initSidePanels();
    updateMissionHUD();

    if (battleOpponentData) {
        document.getElementById("hud-battle-info").classList.remove("hidden");
        document.getElementById("hud-opp-score").textContent = battleOpponentData.name + " " + battleOpponentData.score.toLocaleString() + "SVP";
    } else {
        document.getElementById("hud-battle-info").classList.add("hidden");
    }

    isPlaying = true;
    playBGM();
    if (rafId) cancelAnimationFrame(rafId);
    rafId = requestAnimationFrame(gameLoop);

    // 첫 플레이 또는 매번 튜토리얼
    if (isFirstPlay) {
        isFirstPlay = false;
        showTutorial();
    }
}

function resizeCanvas() {
    const rect = canvas.getBoundingClientRect();
    const dpr = Math.min(window.devicePixelRatio || 1, 2);
    CW = rect.width; CH = rect.height;
    canvas.width = CW * dpr; canvas.height = CH * dpr;
    ctx.scale(dpr, dpr);
    targetX = getLaneX(playerLane);
    if (!isPlaying) { playerX = targetX; }
    playerY = CH - 130;
}

window.addEventListener("resize", () => { if (isPlaying) resizeCanvas(); });

// ============================================================
// CONTROLS
// ============================================================
function getLaneX(lane) { return (CW / 3) * lane + (CW / 6); }
function moveLane(d) {
    const n = playerLane + d;
    if (n >= 0 && n <= 2) { playerLane = n; targetX = getLaneX(n); }
}
function doJump() { if (jumpOff === 0 && !isSliding) { velY = 15.5; playSound("jump"); } }
function doSlide() { if (jumpOff === 0 && !isSliding) { isSliding = true; slideTimer = 32; playSound("jump"); } }

function toggleCtrlMode() {
    ctrlMode = ctrlMode === "touchpad" ? "swipe" : "touchpad";
    document.getElementById("ctrl-label").textContent = ctrlMode === "touchpad" ? "터치패드" : "스와이프";
    document.getElementById("ctrl-hint").textContent = ctrlMode === "touchpad" ? "하단 버튼으로 조작" : "화면 스와이프로 조작";
    const vc = document.getElementById("vcontroller");
    vc.style.opacity = ctrlMode === "touchpad" ? "1" : "0.2";
    vc.style.pointerEvents = ctrlMode === "touchpad" ? "auto" : "none";
}

// Button bindings (prevent ghost clicks)
function bindBtn(id, fn) {
    const btn = document.getElementById(id);
    if (!btn) return;
    let lastTouch = 0;
    btn.addEventListener("touchstart", e => { e.preventDefault(); lastTouch = Date.now(); unlockAudio(); fn(); }, {passive:false});
    btn.addEventListener("mousedown", e => { if (Date.now() - lastTouch < 400) return; e.preventDefault(); fn(); });
}
bindBtn("vbtn-left",  () => moveLane(-1));
bindBtn("vbtn-right", () => moveLane(1));
bindBtn("vbtn-jump",  doJump);
bindBtn("vbtn-slide", doSlide);

// Keyboard
window.addEventListener("keydown", e => {
    if (!isPlaying) return;
    const prevent = ["ArrowUp","ArrowDown","ArrowLeft","ArrowRight"," ","w","a","s","d","W","A","S","D"];
    if (prevent.includes(e.key)) e.preventDefault();
    const k = e.key.toLowerCase();
    if (k==="arrowleft"||k==="a") moveLane(-1);
    else if (k==="arrowright"||k==="d") moveLane(1);
    else if (k==="arrowup"||k==="w"||k===" ") doJump();
    else if (k==="arrowdown"||k==="s") doSlide();
    else if (k==="q") activateSkill();
});

// Swipe on canvas
let swX=0, swY=0;
canvas.addEventListener("touchstart", e => { if(ctrlMode!=="swipe") return; swX=e.touches[0].clientX; swY=e.touches[0].clientY; }, {passive:true});
canvas.addEventListener("touchend", e => {
    if (!isPlaying || ctrlMode !== "swipe") return;
    const dx = e.changedTouches[0].clientX - swX;
    const dy = e.changedTouches[0].clientY - swY;
    if (Math.abs(dx) > Math.abs(dy)) { if(dx>35)moveLane(1); else if(dx<-35)moveLane(-1); }
    else { if(dy<-35)doJump(); else if(dy>35)doSlide(); }
}, {passive:true});

canvas.addEventListener("touchmove", e => e.preventDefault(), {passive:false});

// ============================================================
// SKILL
// ============================================================
function activateSkill() {
    if (skillCharge < 100 || isSkillActive) return;
    isSkillActive = true; skillCharge = 0; skillTimer = 300;
    playSound("skill");
    document.getElementById("hud-skill-bar").style.width = "0%";

    const flash = document.getElementById("skill-flash");
    const nameEl = document.getElementById("skill-name");
    const card = document.getElementById("skill-card");

    const skillNames = {hunmin:"상생 자석 활성화!", sunsik:"무적 실드 가동!", daim:"가치 혜안 (2X점수)!"};
    nameEl.textContent = skillNames[selectedChar] || "";

    flash.style.opacity = "1"; card.style.transform = "scale(1)";
    setTimeout(() => { flash.style.opacity = "0"; card.style.transform = "scale(0.75)"; }, 1200);
    resetSkillBtn();
}

function addSkillCharge(v) {
    if (isSkillActive) return;
    skillCharge = Math.min(100, skillCharge + v);
    document.getElementById("hud-skill-bar").style.width = skillCharge + "%";
    if (skillCharge >= 100) {
        const btn = document.getElementById("btn-skill");
        btn.className = "touch-manipulation h-14 rounded-2xl bg-[#091f3d] border-2 border-sky-400 text-sky-400 flex flex-col items-center justify-center font-black text-[9px] shadow-lg opacity-100 cursor-pointer";
        document.getElementById("skill-btn-label").textContent = "스킬!";
    }
}

function resetSkillBtn() {
    const btn = document.getElementById("btn-skill");
    btn.className = "touch-manipulation h-14 rounded-2xl bg-slate-900 border border-slate-700/40 text-slate-500 flex flex-col items-center justify-center font-black text-[9px] opacity-40 cursor-not-allowed";
    document.getElementById("skill-btn-label").textContent = "대기중";
}

// ============================================================
// GAME LOOP
// ============================================================
function gameLoop() {
    if (!isPlaying || isPaused) return;
    frame++;
    distRun += 0.45;

    // 스테이지 클리어 타이머 처리
    if (stageClearTimer > 0) {
        stageClearTimer--;
        if (stageClearTimer === 0) {
            const overlay = document.getElementById("stage-clear-overlay");
            overlay.classList.add("hidden");
            overlay.style.display = "none";
            setTimeout(() => { overlay.style.display = ""; }, 100);
            accumulatedScore += Math.round(gameScore);
            gameScore = 0;
            uniqueCollected.clear();
            itemCounts = {}; PUBLIC_PURCHASES.forEach(p => itemCounts[p.id] = 0);
            document.getElementById("hud-uniques").textContent = "수집: 0/12";
        }
    }

    // 콤보 타이머 감소
    if (comboTimer > 0) {
        comboTimer--;
        if (comboTimer === 0) { comboCount = 0; comboMultiplier = 1; }
    }
    if (comboHideTimer > 0) {
        comboHideTimer--;
        if (comboHideTimer === 0) document.getElementById("combo-display").classList.add("hidden");
    }

    // PB 체크
    const curTotal = Math.round(accumulatedScore + gameScore);
    if (!pbNotified && curTotal > personalBest && personalBest > 0) {
        pbNotified = true;
        document.getElementById("pb-notify").classList.remove("hidden");
        setTimeout(() => document.getElementById("pb-notify").classList.add("hidden"), 3000);
    }

    updateStation();
    updatePlayer();
    updateObstacles();
    updateItems();
    updateParticles();
    updateScenery();

    render();

    document.getElementById("hud-score").textContent = curTotal.toLocaleString();
    document.getElementById("hud-uniques").textContent = "수집: " + uniqueCollected.size + "/12";
    document.getElementById("hud-stage").textContent = "STAGE " + currentStage;

    rafId = requestAnimationFrame(gameLoop);
}

function updateStation() {
    let name = MAP_STATIONS[0].name;
    MAP_STATIONS.forEach(s => { if (distRun >= s.dist) name = s.name; });
    document.getElementById("hud-station").textContent = "📍 " + name;
}

function updatePlayer() {
    playerX += (targetX - playerX) * 0.22;
    if (velY !== 0 || jumpOff > 0) {
        jumpOff += velY; velY -= 0.8;
        if (jumpOff <= 0) { jumpOff = 0; velY = 0; }
    }
    if (isSliding) { slideTimer--; if (slideTimer <= 0) isSliding = false; }
    if (isSkillActive) { skillTimer--; if (skillTimer <= 0) { isSkillActive = false; resetSkillBtn(); } }
}

function updateObstacles() {
    if (frame % 85 === 0 && Math.random() < 0.75) {
        // 장애물 타입: "hurdle"(낮은 허들, 슬라이드로 통과) 또는 "tnt"(TNT 폭탄, 점프로만 통과)
        const type = Math.random() < 0.6 ? "hurdle" : "tnt";
        obstacles.push({x:getLaneX(Math.floor(Math.random()*3)), y:-60, type, w: type==="tnt" ? 22 : 54, h: type==="hurdle" ? 36 : 22});
    }
    for (let i = obstacles.length-1; i >= 0; i--) {
        const o = obstacles[i];
        o.y += gameSpeed;
        const pY = playerY - jumpOff;
        const pTop = pY - (isSliding ? 16 : 38); // 슬라이딩 시 히트박스 높이 축소
        const pBot = pY + 6; // 발 아래 여유
        const hitW = 11;

        if (o.type === "tnt") {
            const bombR = 11;
            const dx = playerX - o.x;
            const dy = (playerY - jumpOff) - o.y;
            const dist = Math.sqrt(dx*dx + dy*dy);
            if (dist < bombR + 10 && jumpOff < 20) {
                if (isSkillActive && selectedChar === "sunsik") {
                    playSound("crash"); createExplosion(o.x, o.y, "#f97316");
                    obstacles.splice(i, 1); gameScore += 400; continue;
                }
                playSound("crash"); triggerRevival(); return;
            }
            // 폭탄을 점프로 통과 (y 기준으로 지나쳤을 때)
            if (!o._counted && o.y > playerY + 20 && jumpOff >= 20) {
                o._counted = true;
                missionStats.bombJumped++;
            }
        } else if (Math.abs(playerX - o.x) < hitW + o.w/2 - 4) {
            let hit = false;
            if (o.type === "hurdle") {
                const barH = 8;
                const hurdleBarTop = o.y - o.h / 2;
                const hurdleBarBot = hurdleBarTop + barH + 4;
                const barOverlap = pTop < hurdleBarBot && pBot > hurdleBarTop;
                if (barOverlap && !isSliding && jumpOff < 8) hit = true;
                // 허들 슬라이드 통과 카운팅
                if (!o._counted && o.y > playerY + 10 && isSliding) {
                    o._counted = true;
                    missionStats.hurdlePassed++;
                }
            }
            if (hit) {
                if (isSkillActive && selectedChar === "sunsik") {
                    playSound("crash"); createExplosion(o.x, o.y, "#3b82f6");
                    obstacles.splice(i, 1); gameScore += 400; continue;
                }
                playSound("crash"); triggerRevival(); return;
            }
        }
        if (o.y > CH + 60) obstacles.splice(i, 1);
    }
}

function updateItems() {
    // #7 골든 아이템 스폰 (5% 확률)
    if (frame % 40 === 0) {
        const isGolden = Math.random() < 0.05;
        const item = PUBLIC_PURCHASES[Math.floor(Math.random()*12)];
        items.push({x:getLaneX(Math.floor(Math.random()*3)), y:-40, item, size: isGolden ? 38 : 34, golden: isGolden});
    }
    for (let i = items.length-1; i >= 0; i--) {
        const e = items[i];
        e.y += gameSpeed;
        if (isSkillActive && selectedChar === "hunmin") {
            const dx = playerX - e.x, dy = (playerY - jumpOff) - e.y;
            e.x += dx * 0.18; e.y += dy * 0.18;
        }
        if (Math.abs(playerX - e.x) < 26 && Math.abs((playerY-jumpOff) - e.y) < 30) {
            playSound("collect");

            // #7 골든 아이템 보너스
            if (e.golden) {
                createExplosion(e.x, e.y, "#fbbf24");
                createExplosion(e.x, e.y, "#f59e0b");
                gameScore += 500;
                showGoldenToast();
            } else {
                createParticles(e.x, e.y, e.item.color);
            }

            itemCounts[e.item.id]++;
            uniqueCollected.add(e.item.id);
            totalCollected++;
            addSkillCharge(8);
            if (!e.golden) showToast(e.item);

            // #9 콤보 시스템
            comboCount++;
            comboTimer = 120; // 2초 안에 다음 수집해야 콤보 유지
            missionStats.maxCombo = Math.max(missionStats.maxCombo, comboCount);
            missionStats.itemsCollected++;
            if (comboCount >= 3) {
                comboMultiplier = comboCount >= 10 ? 2.0 : comboCount >= 5 ? 1.5 : 1.2;
                showComboDisplay();
            }

            let base = 0;
            PUBLIC_PURCHASES.forEach(p => base += itemCounts[p.id] * 100);
            const skillMult = (isSkillActive && selectedChar === "daim") ? 2 : 1;
            gameScore = base * (1 + uniqueCollected.size / 12) * comboMultiplier * skillMult;

            // 스테이지 클리어 체크
            if (uniqueCollected.size >= 12 && stageClearTimer === 0 && currentStage < 10) {
                missionStats.stagesCleared++;
                if (currentStage === 1) missionStats.stage1Clear = 1;
                currentStage++;
                gameSpeed = 2.6 * Math.pow(1.05, currentStage - 1);
                stageClearTimer = 180;
                document.getElementById("stage-clear-num").textContent = "STAGE " + currentStage + " 시작!";
                const overlay = document.getElementById("stage-clear-overlay");
                overlay.classList.remove("hidden");
                clearTimeout(overlay._forceHideTimer);
                overlay._forceHideTimer = setTimeout(() => {
                    if (stageClearTimer > 0) { stageClearTimer = 0; overlay.classList.add("hidden"); }
                }, 4000);
            } else if (uniqueCollected.size >= 12 && currentStage >= 10) {
                playSound("showEnding");
                setTimeout(() => showEnding(), 400);
            }

            checkMissions();
            updateMissionHUD();
            items.splice(i, 1); continue;
        }
        if (e.y > CH + 50) items.splice(i, 1);
    }
}

function createParticles(x, y, color) {
    if (particles.length > 120) return;
    for (let i=0; i<7; i++) particles.push({x,y,vx:(Math.random()-.5)*6,vy:(Math.random()-.5)*6,color,size:2+Math.random()*3,life:20});
}
function createExplosion(x, y, color) {
    if (particles.length > 120) return;
    for (let i=0; i<12; i++) particles.push({x,y,vx:(Math.random()-.5)*10,vy:(Math.random()-.5)*10,color,size:3+Math.random()*4,life:28});
}
function updateParticles() {
    for (let i=particles.length-1;i>=0;i--) {
        const p=particles[i]; p.x+=p.vx; p.y+=p.vy; p.life--;
        if(p.life<=0)particles.splice(i,1);
    }
}

// ============================================================
// #1 PAUSE
// ============================================================
function togglePause() {
    if (!isPlaying) return;
    isPaused = !isPaused;
    document.getElementById("pause-overlay").classList.toggle("hidden", !isPaused);
    document.getElementById("btn-pause").textContent = isPaused ? "▶" : "⏸";
    if (!isPaused) { rafId = requestAnimationFrame(gameLoop); }
    else { if (rafId) cancelAnimationFrame(rafId); }
}
function confirmQuit() {
    isPaused = false;
    document.getElementById("pause-overlay").classList.add("hidden");
    isPlaying = false;
    if (rafId) cancelAnimationFrame(rafId);
    stopBGM();
    showScreen("menu");
}
window.addEventListener("keydown", e => { if (e.key === "Escape" && isPlaying) togglePause(); });

// ============================================================
// #3 REVIVAL SYSTEM
// ============================================================
function triggerRevival() {
    if (revivalUsed || skillCharge < 100) {
        endGame(); return;
    }
    isPlaying = false;
    if (rafId) cancelAnimationFrame(rafId);
    const overlay = document.getElementById("revival-overlay");
    overlay.classList.remove("hidden");
    let count = 3;
    document.getElementById("revival-countdown").textContent = count;
    revivalTimer = setInterval(() => {
        count--;
        document.getElementById("revival-countdown").textContent = count;
        if (count <= 0) {
            clearInterval(revivalTimer);
            // 자동 종료 (버튼 안 누르면)
            overlay.classList.add("hidden");
            endGame();
        }
    }, 1000);
}
function doRevive() {
    clearInterval(revivalTimer);
    document.getElementById("revival-overlay").classList.add("hidden");
    revivalUsed = true;
    skillCharge = 0;
    document.getElementById("hud-skill-bar").style.width = "0%";
    resetSkillBtn();
    // 무적 2초
    isSkillActive = true; skillTimer = 120;
    isPlaying = true;
    obstacles = obstacles.filter(o => o.y < playerY - 60);
    rafId = requestAnimationFrame(gameLoop);
}
function confirmEndGame() {
    clearInterval(revivalTimer);
    document.getElementById("revival-overlay").classList.add("hidden");
    endGame();
}

// ============================================================
// #9 COMBO DISPLAY
// ============================================================
function showComboDisplay() {
    const el = document.getElementById("combo-display");
    const txt = document.getElementById("combo-text");
    const mult = document.getElementById("combo-mult");
    txt.textContent = comboCount + " COMBO!";
    mult.textContent = "× " + comboMultiplier.toFixed(1) + " 점수 배율";
    el.classList.remove("hidden");
    el.style.transform = "translateX(-50%) scale(1.2)";
    setTimeout(() => { el.style.transform = "translateX(-50%) scale(1)"; }, 150);
    comboHideTimer = 90;
}

// ============================================================
// #7 GOLDEN ITEM TOAST
// ============================================================
function showGoldenToast() {
    const wrap = document.getElementById("toast-wrap");
    document.getElementById("toast-title").textContent = "✨ LUCKY GOLDEN ITEM! +500 SVP";
    document.getElementById("toast-msg").textContent = "반짝이는 황금 아이템을 획득했습니다!";
    document.getElementById("toast-icon").innerHTML = '<span style="font-size:24px">⭐</span>';
    wrap.style.opacity = "1"; wrap.style.transform = "translateY(0)";
    setTimeout(() => { wrap.style.opacity = "0"; wrap.style.transform = "translateY(-8px)"; }, 2200);
}

// ============================================================
// #11 DAILY MISSIONS
// ============================================================
function initDailyMissions() {
    const today = new Date().toISOString().split("T")[0];
    const seed = today.replace(/-/g,"");
    const idx = [parseInt(seed)%6, (parseInt(seed)+2)%6, (parseInt(seed)+4)%6];
    todayMissions = idx.map(i => ({...MISSIONS_POOL[i], done: false}));
}
function checkMissions() {
    todayMissions.forEach(m => {
        if (!m.done && missionStats[m.stat] >= m.target) {
            m.done = true;
            gameScore += m.bonus;
            showMissionComplete(m);
        }
    });
}
function showMissionComplete(m) {
    const wrap = document.getElementById("toast-wrap");
    document.getElementById("toast-title").textContent = "📋 미션 완료! +" + m.bonus + " SVP";
    document.getElementById("toast-msg").textContent = m.desc;
    document.getElementById("toast-icon").innerHTML = '<span style="font-size:24px">✅</span>';
    wrap.style.opacity = "1"; wrap.style.transform = "translateY(0)";
    setTimeout(() => { wrap.style.opacity = "0"; wrap.style.transform = "translateY(-8px)"; }, 2200);
}
function updateMissionHUD() {
    const el = document.getElementById("mission-list-hud");
    if (!todayMissions.length) return;
    document.getElementById("mission-banner").classList.remove("hidden");
    el.innerHTML = todayMissions.map(m => {
        const prog = Math.min(missionStats[m.stat], m.target);
        const pct = Math.round(prog / m.target * 100);
        const color = m.done ? "text-emerald-400" : "text-slate-300";
        return `<div class="${color} text-[8px] font-bold">${m.done?"✅":"⬜"} ${m.desc} (${prog}/${m.target})</div>`;
    }).join("");
}

// ============================================================
// TUTORIAL
// ============================================================
function showTutorial() {
    isPaused = true;
    document.getElementById("tutorial-overlay").classList.remove("hidden");
}
function closeTutorial() {
    document.getElementById("tutorial-overlay").classList.add("hidden");
    isPaused = false;
    rafId = requestAnimationFrame(gameLoop);
}

// ============================================================
// #12 ENDING SEQUENCE (10 STAGE CLEAR)
// ============================================================
function showEnding() {
    isPlaying = false;
    if (rafId) cancelAnimationFrame(rafId);
    stopBGM();
    // 폭죽 파티클 버스트
    for (let b = 0; b < 8; b++) {
        setTimeout(() => {
            const x = CW * (0.2 + Math.random() * 0.6);
            const y = CH * (0.2 + Math.random() * 0.5);
            const colors = ["#fbbf24","#ef4444","#22d3ee","#a855f7","#86efac","#f472b6"];
            createExplosion(x, y, colors[Math.floor(Math.random()*colors.length)]);
        }, b * 180);
    }
    // 엔딩 오버레이
    setTimeout(() => {
        const endEl = document.createElement("div");
        endEl.id = "ending-overlay";
        endEl.style.cssText = "position:absolute;inset:0;z-index:60;background:linear-gradient(160deg,#0a0020,#001a3a);display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:2rem";
        endEl.innerHTML = `
            <div style="font-size:3rem;margin-bottom:0.5rem">&#127882;&#127882;&#127882;</div>
            <div style="font-size:0.65rem;color:#38bdf8;font-weight:900;letter-spacing:0.15em;margin-bottom:0.25rem">ALL STAGES CLEARED!</div>
            <h2 style="font-size:1.4rem;font-weight:900;color:#fff;font-family:Orbitron,sans-serif;margin-bottom:0.5rem">조폐공사<br>공공구매 완전 정복!</h2>
            <p style="font-size:0.7rem;color:#94a3b8;margin-bottom:1rem">전국 5대 거점을 완주한 진정한 상생 원정대!</p>
            <div style="background:rgba(14,165,233,0.1);border:1px solid rgba(14,165,233,0.4);border-radius:1rem;padding:0.75rem 1.5rem;margin-bottom:1.5rem">
                <div style="font-size:0.7rem;color:#94a3b8">최종 SVP 점수</div>
                <div style="font-size:1.75rem;font-weight:900;color:#38bdf8;font-family:Orbitron,sans-serif">${Math.round(accumulatedScore+gameScore).toLocaleString()}</div>
            </div>
            <button onclick="document.getElementById('ending-overlay').remove();endGame();" style="background:linear-gradient(to right,#0ea5e9,#6366f1);padding:0.85rem 2.5rem;border-radius:1rem;font-weight:900;font-size:0.85rem;border:none;color:white;cursor:pointer">&#128293; 결과 보기</button>`;
        document.getElementById("screen-game").appendChild(endEl);
    }, 1500);
}
function updateScenery() {
    scenery.forEach(s => {
        s.y += gameSpeed * 0.4;
        if (s.y > CH + 80) {
            s.y = -80;
            s.x = Math.random()<.5 ? 15+Math.random()*20 : CW-(35+Math.random()*20);
            s.type = ["tree","block","cloud"][Math.floor(Math.random()*3)];
            // 제품 패널도 랜덤으로 새로고침
            s.productIdx = (s.productIdx + 1) % MINT_PRODUCTS.length;
        }
    });
    // 사이드 제품 패널 스크롤
    SIDE_PANELS.forEach(p => {
        p.y += gameSpeed * 0.35;
        if (p.y > CH + 80) {
            p.y = -80;
            p.idx = (p.idx + 1) % MINT_PRODUCTS.length;
        }
    });
}

// 조폐공사 제품 목록 (실제 제품 12종 + 추가)
const MINT_PRODUCTS = [
    { key:"hwapye",   name:"대한민국\n화폐",    color:"#16a34a",  accent:"#bbf7d0" },
    { key:"yeogwon",  name:"차세대\n전자여권",  color:"#1d4ed8",  accent:"#bfdbfe" },
    { key:"jumin",    name:"주민등록증",        color:"#7c3aed",  accent:"#ede9fe" },
    { key:"goldbar",  name:"골드바",           color:"#ca8a04",  accent:"#fef08a" },
    { key:"silverbar",name:"실버바",           color:"#64748b",  accent:"#e2e8f0" },
    { key:"jiyeok",   name:"지역사랑\n상품권",  color:"#0891b2",  accent:"#bae6fd" },
    { key:"onnuri",   name:"온누리\n상품권",    color:"#059669",  accent:"#a7f3d0" },
    { key:"hunjang",  name:"훈장",             color:"#b45309",  accent:"#fde68a" },
    { key:"medal",    name:"메달",             color:"#d97706",  accent:"#fef3c7" },
    { key:"upyo",     name:"우표",             color:"#dc2626",  accent:"#fee2e2" },
    { key:"mobshin",  name:"모바일\n신분증",    color:"#0284c7",  accent:"#bae6fd" },
    { key:"mobhwa",   name:"모바일\n지역화폐",  color:"#15803d",  accent:"#bbf7d0" },
];

// 사이드 패널 초기화 (게임 영역 양쪽)
let SIDE_PANELS = [];
function initSidePanels() {
    SIDE_PANELS = [];
    const count = 6;
    const gap = Math.max(80, CH / count); // 패널 간격
    for (let i = 0; i < count; i++) {
        // 왼쪽 사이드
        SIDE_PANELS.push({ side:"left",  y: gap*i - 90, idx: i % MINT_PRODUCTS.length });
        // 오른쪽 사이드
        SIDE_PANELS.push({ side:"right", y: gap*i - 50, idx: (i + Math.floor(MINT_PRODUCTS.length/2)) % MINT_PRODUCTS.length });
    }
}

// ============================================================
// RENDER
// ============================================================
function render() {
    const theme = STAGE_THEMES[Math.min(currentStage - 1, STAGE_THEMES.length - 1)];
    ctx.fillStyle = theme.bg;
    ctx.fillRect(0, 0, CW, CH);
    renderTerrain(theme);
    renderSidePanels();
    renderTracks(theme);
    renderObstaclesR();
    renderItemsR();
    renderParticlesR();
    renderPlayerR();
}

function renderSidePanels() {
    SIDE_PANELS.forEach(p => {
        const product = MINT_PRODUCTS[p.idx % MINT_PRODUCTS.length];
        const cx = p.side === "left" ? 15 : CW - 15;
        const w = 30, h = 68;
        const px = cx - w / 2;
        const py = p.y - h / 2;

        ctx.save();

        // 패널 배경
        ctx.fillStyle = "rgba(4,14,32,0.92)";
        ctx.beginPath();
        ctx.roundRect(px, py, w, h, 6);
        ctx.fill();

        // 상단 색상 바
        ctx.fillStyle = product.color;
        ctx.beginPath();
        ctx.roundRect(px + 2, py + 2, w - 4, 4, [3, 3, 0, 0]);
        ctx.fill();

        // 테두리
        ctx.strokeStyle = product.color + "cc";
        ctx.lineWidth = 1.2;
        ctx.beginPath();
        ctx.roundRect(px, py, w, h, 6);
        ctx.stroke();

        // 제품별 아이콘 그리기
        const ix = cx, iy = py + 22;
        drawMintProductIcon(ctx, product.key, ix, iy, product.color, product.accent);

        // 제품명 (줄바꿈 지원)
        ctx.fillStyle = "#e2e8f0";
        ctx.font = "bold 5.5px 'Noto Sans KR', sans-serif";
        ctx.textAlign = "center";
        ctx.textBaseline = "middle";
        const lines = product.name.split("\n");
        const textY = py + h - (lines.length === 2 ? 14 : 9);
        lines.forEach((line, i) => {
            ctx.fillText(line, cx, textY + i * 9);
        });

        ctx.restore();
    });
}

function drawMintProductIcon(c, key, cx, cy, color, accent) {
    c.save();
    c.translate(cx, cy);
    const s = 11; // base scale

    switch(key) {
        case "hwapye": // 화폐 - 지폐 모양
            c.fillStyle = color;
            c.beginPath(); c.roundRect(-s*1.1, -s*.6, s*2.2, s*1.2, 2); c.fill();
            c.fillStyle = accent;
            c.beginPath(); c.roundRect(-s*.55, -s*.3, s*1.1, s*.6, 2); c.fill();
            c.fillStyle = color;
            c.font = `bold ${s*.7}px sans-serif`; c.textAlign="center"; c.textBaseline="middle";
            c.fillText("₩", 0, 0);
            // 지폐 테두리 선
            c.strokeStyle = accent + "88"; c.lineWidth = .8;
            c.beginPath(); c.roundRect(-s*1.1, -s*.6, s*2.2, s*1.2, 2); c.stroke();
            break;

        case "yeogwon": // 전자여권 - 책 형태
            c.fillStyle = color;
            c.beginPath(); c.roundRect(-s*.85, -s*1.05, s*1.7, s*2.1, 2); c.fill();
            // 여권 문양 (원형)
            c.strokeStyle = accent; c.lineWidth = .7;
            c.beginPath(); c.arc(0, -s*.1, s*.55, 0, Math.PI*2); c.stroke();
            c.beginPath(); c.arc(0, -s*.1, s*.3, 0, Math.PI*2); c.stroke();
            // 가로선들
            c.fillStyle = accent + "aa";
            [-s*.55, -s*.35, -s*.15].forEach(yy => {
                c.fillRect(-s*.5, yy + s*.75, s*1.0, 1.2);
            });
            // 칩 표시
            c.fillStyle = accent;
            c.beginPath(); c.roundRect(-s*.22, s*.6, s*.44, s*.3, 1); c.fill();
            c.strokeStyle = color; c.lineWidth = .5;
            c.beginPath(); c.moveTo(-s*.11, s*.6); c.lineTo(-s*.11, s*.9); c.stroke();
            c.beginPath(); c.moveTo(0, s*.6); c.lineTo(0, s*.9); c.stroke();
            c.beginPath(); c.moveTo(s*.11, s*.6); c.lineTo(s*.11, s*.9); c.stroke();
            break;

        case "jumin": // 주민등록증 - ID카드
            c.fillStyle = color;
            c.beginPath(); c.roundRect(-s*1.05, -s*.65, s*2.1, s*1.3, 2); c.fill();
            // 태극 원
            c.fillStyle = accent;
            c.beginPath(); c.arc(-s*.55, 0, s*.38, 0, Math.PI*2); c.fill();
            c.fillStyle = "#dc2626";
            c.beginPath(); c.arc(-s*.55, -s*.19, s*.19, 0, Math.PI); c.fill();
            c.fillStyle = "#1d4ed8";
            c.beginPath(); c.arc(-s*.55, s*.19, s*.19, Math.PI, Math.PI*2); c.fill();
            // 텍스트 줄
            c.fillStyle = accent + "cc";
            [s*-.28, s*.0, s*.28].forEach(yy => {
                c.fillRect(-s*.05, yy-1, s*.95, 2);
            });
            break;

        case "goldbar": // 골드바
            // 그림자
            c.fillStyle = "rgba(0,0,0,0.3)";
            c.beginPath(); c.ellipse(s*.1, s*.85, s*.85, s*.28, 0, 0, Math.PI*2); c.fill();
            // 바 본체
            const grd = c.createLinearGradient(-s*.9, -s*.5, s*.9, s*.5);
            grd.addColorStop(0, "#fbbf24");
            grd.addColorStop(0.4, "#fef08a");
            grd.addColorStop(0.6, "#f59e0b");
            grd.addColorStop(1, "#92400e");
            c.fillStyle = grd;
            c.beginPath();
            c.moveTo(-s*.7, -s*.6); c.lineTo(s*.7, -s*.6);
            c.lineTo(s*.9, -s*.1); c.lineTo(s*.9, s*.5);
            c.lineTo(-s*.9, s*.5); c.lineTo(-s*.9, -s*.1);
            c.closePath(); c.fill();
            // 상단면
            const topG = c.createLinearGradient(-s*.7, -s*.6, s*.7, -s*.1);
            topG.addColorStop(0, "#fef9c3");
            topG.addColorStop(1, "#fde68a");
            c.fillStyle = topG;
            c.beginPath();
            c.moveTo(-s*.7, -s*.6); c.lineTo(s*.7, -s*.6);
            c.lineTo(s*.9, -s*.1); c.lineTo(-s*.9, -s*.1);
            c.closePath(); c.fill();
            // 양각 테두리
            c.strokeStyle = "#92400e"; c.lineWidth = .7;
            c.beginPath(); c.roundRect(-s*.75, -s*.05, s*1.5, s*.45, 1); c.stroke();
            // 금 텍스트
            c.fillStyle = "#78350f"; c.font = `bold ${s*.65}px sans-serif`;
            c.textAlign = "center"; c.textBaseline = "middle";
            c.fillText("Au", 0, s*.22);
            break;

        case "silverbar": // 실버바
            const sgrd = c.createLinearGradient(-s*.9, -s*.5, s*.9, s*.5);
            sgrd.addColorStop(0, "#94a3b8");
            sgrd.addColorStop(0.4, "#f1f5f9");
            sgrd.addColorStop(0.6, "#cbd5e1");
            sgrd.addColorStop(1, "#334155");
            c.fillStyle = sgrd;
            c.beginPath();
            c.moveTo(-s*.7, -s*.6); c.lineTo(s*.7, -s*.6);
            c.lineTo(s*.9, -s*.1); c.lineTo(s*.9, s*.5);
            c.lineTo(-s*.9, s*.5); c.lineTo(-s*.9, -s*.1);
            c.closePath(); c.fill();
            const stopG = c.createLinearGradient(-s*.7, -s*.6, s*.7, -s*.1);
            stopG.addColorStop(0, "#f8fafc"); stopG.addColorStop(1, "#e2e8f0");
            c.fillStyle = stopG;
            c.beginPath();
            c.moveTo(-s*.7, -s*.6); c.lineTo(s*.7, -s*.6);
            c.lineTo(s*.9, -s*.1); c.lineTo(-s*.9, -s*.1);
            c.closePath(); c.fill();
            c.strokeStyle = "#475569"; c.lineWidth = .7;
            c.beginPath(); c.roundRect(-s*.75, -s*.05, s*1.5, s*.45, 1); c.stroke();
            c.fillStyle = "#334155"; c.font = `bold ${s*.65}px sans-serif`;
            c.textAlign = "center"; c.textBaseline = "middle";
            c.fillText("Ag", 0, s*.22);
            break;

        case "jiyeok": // 지역사랑 상품권 - 상품권 느낌
            c.fillStyle = color;
            c.beginPath(); c.roundRect(-s*.95, -s*.65, s*1.9, s*1.3, 3); c.fill();
            // 물결 무늬
            c.strokeStyle = accent + "66"; c.lineWidth = .8; c.setLineDash([2,2]);
            c.beginPath(); c.roundRect(-s*.8, -s*.5, s*1.6, s*1.0, 2); c.stroke();
            c.setLineDash([]);
            // 하트 + 지역 표시
            c.fillStyle = accent;
            c.font = `${s*.85}px sans-serif`; c.textAlign="center"; c.textBaseline="middle";
            c.fillText("♥", 0, s*.05);
            c.fillStyle = accent + "cc"; c.font = `bold ${s*.45}px 'Noto Sans KR',sans-serif`;
            c.fillText("지역사랑", 0, -s*.38);
            break;

        case "onnuri": // 온누리 상품권
            c.fillStyle = color;
            c.beginPath(); c.roundRect(-s*.95, -s*.65, s*1.9, s*1.3, 3); c.fill();
            c.strokeStyle = accent + "55"; c.lineWidth = .8; c.setLineDash([2,2]);
            c.beginPath(); c.roundRect(-s*.8, -s*.5, s*1.6, s*1.0, 2); c.stroke();
            c.setLineDash([]);
            // 오누리 전통 무늬 (원)
            c.strokeStyle = accent; c.lineWidth = 1;
            c.beginPath(); c.arc(0, s*.1, s*.38, 0, Math.PI*2); c.stroke();
            c.fillStyle = accent + "44"; c.fill();
            c.fillStyle = accent; c.font = `bold ${s*.38}px 'Noto Sans KR',sans-serif`;
            c.textAlign="center"; c.textBaseline="middle";
            c.fillText("온누리", 0, s*.1);
            break;

        case "hunjang": // 훈장
            // 별 형태
            c.fillStyle = color;
            for(let i=0;i<5;i++){
                const a=-Math.PI/2+(i/5)*Math.PI*2;
                const a2=a+Math.PI/5;
                c.beginPath();
                c.moveTo(Math.cos(a)*s*.85, Math.sin(a)*s*.85);
                c.lineTo(Math.cos(a2)*s*.38, Math.sin(a2)*s*.38);
                c.lineTo(Math.cos(a+Math.PI*2/5)*s*.85, Math.sin(a+Math.PI*2/5)*s*.85);
                c.lineTo(0,0); c.closePath(); c.fill();
            }
            // 중앙 원
            c.fillStyle = accent;
            c.beginPath(); c.arc(0, 0, s*.35, 0, Math.PI*2); c.fill();
            c.fillStyle = color; c.font = `bold ${s*.55}px sans-serif`;
            c.textAlign="center"; c.textBaseline="middle";
            c.fillText("★", 0, s*.04);
            // 리본
            c.fillStyle = "#dc2626";
            c.beginPath(); c.moveTo(-s*.22, s*.85); c.lineTo(0, s*.4); c.lineTo(s*.22, s*.85);
            c.lineTo(s*.1, s*1.05); c.lineTo(0, s*.85); c.lineTo(-s*.1, s*1.05); c.closePath(); c.fill();
            break;

        case "medal": // 메달
            // 리본
            c.fillStyle = "#3b82f6";
            c.fillRect(-s*.25, -s*1.0, s*.5, s*.6);
            c.fillStyle = "#1d4ed8";
            c.fillRect(-s*.25, -s*.7, s*.5, s*.28);
            // 메달 원
            const mGrd = c.createRadialGradient(-s*.2, -s*.2, s*.05, 0, 0, s*.72);
            mGrd.addColorStop(0, "#fef9c3");
            mGrd.addColorStop(0.5, "#fbbf24");
            mGrd.addColorStop(1, "#92400e");
            c.fillStyle = mGrd;
            c.beginPath(); c.arc(0, s*.2, s*.72, 0, Math.PI*2); c.fill();
            c.strokeStyle = "#78350f"; c.lineWidth = 1;
            c.beginPath(); c.arc(0, s*.2, s*.72, 0, Math.PI*2); c.stroke();
            // 별
            c.fillStyle = "#92400e"; c.font = `${s*.75}px sans-serif`;
            c.textAlign="center"; c.textBaseline="middle";
            c.fillText("★", 0, s*.22);
            break;

        case "upyo": // 우표
            // 우표 테두리 (들쭉날쭉)
            c.fillStyle = "#fff";
            c.beginPath(); c.roundRect(-s*.95, -s*.95, s*1.9, s*1.9, 1); c.fill();
            // 들쭉날쭉 효과
            c.fillStyle = "rgba(4,14,32,0.9)";
            const tStep = s*.22;
            for(let xx=-s*.95;xx<s*.9;xx+=tStep){
                c.beginPath(); c.arc(xx+tStep/2, -s*.95, tStep/2.6, 0, Math.PI*2); c.fill();
                c.beginPath(); c.arc(xx+tStep/2,  s*.95, tStep/2.6, 0, Math.PI*2); c.fill();
            }
            for(let yy=-s*.95;yy<s*.9;yy+=tStep){
                c.beginPath(); c.arc(-s*.95, yy+tStep/2, tStep/2.6, 0, Math.PI*2); c.fill();
                c.beginPath(); c.arc( s*.95, yy+tStep/2, tStep/2.6, 0, Math.PI*2); c.fill();
            }
            // 우표 내용
            c.fillStyle = color + "cc";
            c.fillRect(-s*.65, -s*.65, s*1.3, s*1.3);
            // 풍경 (산)
            c.fillStyle = "#16a34a";
            c.beginPath(); c.moveTo(-s*.55, s*.35); c.lineTo(-s*.2, -s*.1); c.lineTo(s*.1, s*.15); c.lineTo(s*.35, -s*.25); c.lineTo(s*.6, s*.35); c.closePath(); c.fill();
            c.fillStyle = "#60a5fa";
            c.fillRect(-s*.65, -s*.65, s*1.3, s*.38);
            // 우표 액면
            c.fillStyle = "#fff"; c.font = `bold ${s*.38}px sans-serif`;
            c.textAlign="center"; c.textBaseline="middle";
            c.fillText("★", 0, -s*.47);
            break;

        case "mobshin": // 모바일 신분증
            // 스마트폰
            c.fillStyle = "#1e293b";
            c.beginPath(); c.roundRect(-s*.75, -s*1.05, s*1.5, s*2.1, 4); c.fill();
            c.strokeStyle = "#475569"; c.lineWidth = .8;
            c.beginPath(); c.roundRect(-s*.75, -s*1.05, s*1.5, s*2.1, 4); c.stroke();
            // 화면
            c.fillStyle = color;
            c.beginPath(); c.roundRect(-s*.6, -s*.88, s*1.2, s*1.65, 2); c.fill();
            // 신분증 아이콘
            c.fillStyle = accent + "dd";
            c.beginPath(); c.roundRect(-s*.45, -s*.72, s*.9, s*.62, 1); c.fill();
            // 얼굴 원
            c.fillStyle = color + "88";
            c.beginPath(); c.arc(-s*.25, -s*.44, s*.18, 0, Math.PI*2); c.fill();
            // 줄
            c.fillStyle = color + "88";
            [s*-.18, s*.0, s*.18].forEach(yy => c.fillRect(-s*.05, yy - s*.65, s*.42, 1.5));
            // 하단 버튼
            c.fillStyle = "#475569";
            c.beginPath(); c.arc(0, s*.9, s*.12, 0, Math.PI*2); c.fill();
            break;

        case "mobhwa": // 모바일 지역화폐
            c.fillStyle = "#1e293b";
            c.beginPath(); c.roundRect(-s*.75, -s*1.05, s*1.5, s*2.1, 4); c.fill();
            c.strokeStyle = "#475569"; c.lineWidth = .8;
            c.beginPath(); c.roundRect(-s*.75, -s*1.05, s*1.5, s*2.1, 4); c.stroke();
            // 화면
            c.fillStyle = color;
            c.beginPath(); c.roundRect(-s*.6, -s*.88, s*1.2, s*1.65, 2); c.fill();
            // C 로고 (Chak 스타일)
            c.strokeStyle = accent; c.lineWidth = 2.5;
            c.beginPath(); c.arc(0, -s*.12, s*.42, Math.PI*.25, Math.PI*1.75); c.stroke();
            c.fillStyle = accent;
            c.beginPath(); c.arc(0, -s*.12, s*.18, 0, Math.PI*2); c.fill();
            // 동전들
            c.fillStyle = "#fbbf24";
            [[-s*.3, s*.7], [0, s*.58], [s*.3, s*.7]].forEach(([xx,yy]) => {
                c.beginPath(); c.ellipse(xx, yy, s*.16, s*.1, 0, 0, Math.PI*2); c.fill();
            });
            c.fillStyle = "#475569";
            c.beginPath(); c.arc(0, s*.9, s*.12, 0, Math.PI*2); c.fill();
            break;

        default:
            c.fillStyle = color;
            c.beginPath(); c.arc(0, 0, s*.8, 0, Math.PI*2); c.fill();
            break;
    }
    c.restore();
}

function renderTerrain(theme) {
    const tc = theme || {bg:"#03091c", road:"#0a1628", accent:"#1e3a5f"};
    const offset = (frame * gameSpeed * 0.4) % 40;
    for (let y = -40; y < CH + 40; y += 40) {
        const ry = y + offset;
        const seed = y;
        drawBlock(15, ry, 30, 40, tc.accent, tc.road, seed);
        drawBlock(CW-15, ry, 30, 40, tc.accent, tc.road, seed);
    }
    scenery.forEach(s => {
        ctx.save(); ctx.translate(s.x, s.y); ctx.scale(s.sc, s.sc);
        if (s.type==="tree") {
            ctx.fillStyle="#1e293b"; ctx.fillRect(-4,10,8,20);
            ctx.fillStyle=tc.road; ctx.fillRect(-18,-10,36,20);
            ctx.fillStyle=tc.accent; ctx.fillRect(-14,-22,28,16);
            ctx.fillStyle=tc.accent+"aa"; ctx.fillRect(-10,-32,20,12);
        } else if (s.type==="block") {
            ctx.fillStyle=tc.road; ctx.fillRect(-10,-10,20,20);
            ctx.fillStyle=tc.accent; ctx.fillRect(-10,5,20,5);
            ctx.fillStyle="#00f2fe88"; ctx.fillRect(-4,-6,4,4); ctx.fillRect(2,2,4,4);
        } else {
            ctx.fillStyle=tc.accent+"44"; ctx.fillRect(-20,-10,40,14); ctx.fillRect(-10,-18,26,10);
        }
        ctx.restore();
    });
    MAP_STATIONS.forEach((st, idx) => {
        const relY = (st.dist - distRun) * 1.5 + CH * 0.4;
        if (relY < -120 || relY > CH+120) return;
        const sx = (idx%2===0) ? 55 : CW-55;
        ctx.save(); ctx.translate(sx, relY);
        ctx.fillStyle="#091e3a"; ctx.fillRect(-22,20,44,10);
        const colors = ["#0284c7","#2563eb","#0369a1","#0b1329"];
        ctx.fillStyle = colors[idx] || "#0284c7"; ctx.fillRect(-18,-25,36,45);
        ctx.fillStyle = distRun >= st.dist ? "#00f2fe" : "#3b82f6";
        ctx.beginPath(); ctx.arc(0,30,5,0,Math.PI*2); ctx.fill();
        ctx.fillStyle="#051126"; ctx.fillRect(-35,-45,70,14);
        ctx.strokeStyle=tc.accent; ctx.strokeRect(-35,-45,70,14);
        ctx.fillStyle="#fff"; ctx.font="bold 7px 'Noto Sans KR'"; ctx.textAlign="center"; ctx.fillText(st.name,0,-35);
        ctx.restore();
    });
}

function drawBlock(x, y, w, h, top, side, seed) {
    ctx.save(); ctx.translate(x, y);
    ctx.fillStyle = side; ctx.fillRect(-w/2,-h/2,w,h);
    ctx.fillStyle = top; ctx.fillRect(-w/2,-h/2,w,h*0.25);
    ctx.fillStyle = top;
    for (let i=-w/2;i<w/2;i+=6) {
        const hash = Math.abs(Math.sin(seed*12.9898+i*78.233))*43758.5453;
        if ((hash-Math.floor(hash))<0.45) ctx.fillRect(i,-h/2+h*0.25,6,6);
    }
    ctx.restore();
}

function renderTracks(theme) {
    const tc = theme || {road:"#0a1628", accent:"#1e3a5f"};
    ctx.fillStyle=tc.road; ctx.fillRect(30,0,CW-60,CH);
    ctx.fillStyle=tc.accent; ctx.fillRect(27,0,3,CH); ctx.fillRect(CW-30,0,3,CH);
    ctx.strokeStyle=tc.accent+"88"; ctx.lineWidth=2.5; ctx.setLineDash([12,12]);
    ctx.beginPath();
    ctx.moveTo(CW/3,0); ctx.lineTo(CW/3,CH);
    ctx.moveTo(CW*2/3,0); ctx.lineTo(CW*2/3,CH);
    ctx.stroke(); ctx.setLineDash([]);
}

function renderPlayerR() {
    ctx.save();
    const hov = Math.sin(frame * 0.18) * 4;
    const bank = (targetX - playerX) * 0.016;
    ctx.translate(playerX, playerY - jumpOff + hov);
    ctx.rotate(bank);
    let sx=1, sy=1;
    if (jumpOff > 0) { sx=0.88; sy=1.12; }
    else if (isSliding) { sx=1.25; sy=0.55; }
    ctx.scale(sx, sy);

    // Skill aura
    if (isSkillActive) {
        ctx.shadowBlur=20;
        ctx.shadowColor = selectedChar==="hunmin"?"#10b981":selectedChar==="sunsik"?"#3b82f6":"#f59e0b";
        ctx.strokeStyle = selectedChar==="hunmin"?"#34d399":selectedChar==="sunsik"?"#60a5fa":"#fbbf24";
        ctx.lineWidth=2;
        ctx.beginPath(); ctx.arc(0,0,24,0,Math.PI*2); ctx.stroke();
        ctx.shadowBlur=0;
    }

    // Draw character image (transparent PNG)
    const sz = 58;
    const charImgEl = CHAR_IMGS[selectedChar];
    if (charImgEl && charImgEl.complete && charImgEl.naturalWidth > 0) {
        const aspect = charImgEl.naturalHeight / charImgEl.naturalWidth;
        const drawH = sz * aspect;
        ctx.drawImage(charImgEl, -sz/2, -drawH*0.86, sz, drawH);
    } else {
        const colors = {hunmin:"#2d5a27",sunsik:"#475569",daim:"#ca8a04"};
        ctx.fillStyle = colors[selectedChar] || "#2d5a27";
        ctx.beginPath(); ctx.arc(0,-5,10,0,Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.moveTo(-8,5); ctx.lineTo(8,5); ctx.lineTo(10,22); ctx.lineTo(-10,22); ctx.closePath(); ctx.fill();
    }
    ctx.restore();
}

function renderObstaclesR() {
    obstacles.forEach(o => {
        ctx.save(); ctx.translate(o.x, o.y);
        if (o.type === "hurdle") {
            // 허들: 좌우 기둥 + 수평 바
            const hw = o.w, hh = o.h;
            const postW = 7, barH = 8;
            const groundY = hh / 2;
            const barY = -hh / 2 + barH / 2;

            // 기둥 그림자
            ctx.fillStyle = "rgba(0,0,0,0.35)";
            ctx.fillRect(-hw/2 + 3, groundY - hh + 4, postW, hh);
            ctx.fillRect( hw/2 - postW + 1, groundY - hh + 4, postW, hh);

            // 좌측 기둥
            const leftGrd = ctx.createLinearGradient(-hw/2, 0, -hw/2 + postW, 0);
            leftGrd.addColorStop(0, "#f97316"); leftGrd.addColorStop(1, "#ea580c");
            ctx.fillStyle = leftGrd;
            ctx.beginPath(); ctx.roundRect(-hw/2, barY, postW, hh, 3); ctx.fill();

            // 우측 기둥
            const rightGrd = ctx.createLinearGradient(hw/2 - postW, 0, hw/2, 0);
            rightGrd.addColorStop(0, "#ea580c"); rightGrd.addColorStop(1, "#f97316");
            ctx.fillStyle = rightGrd;
            ctx.beginPath(); ctx.roundRect(hw/2 - postW, barY, postW, hh, 3); ctx.fill();

            // 수평 바 (상단)
            const barGrd = ctx.createLinearGradient(0, barY, 0, barY + barH);
            barGrd.addColorStop(0, "#fbbf24"); barGrd.addColorStop(0.5, "#f59e0b"); barGrd.addColorStop(1, "#d97706");
            ctx.fillStyle = barGrd;
            ctx.beginPath(); ctx.roundRect(-hw/2, barY, hw, barH, 3); ctx.fill();

            // 바 하이라이트
            ctx.fillStyle = "rgba(255,255,255,0.35)";
            ctx.fillRect(-hw/2 + 4, barY + 1.5, hw - 8, 2.5);

            // 기둥 스트라이프 (운동 허들 느낌)
            ctx.fillStyle = "rgba(255,255,255,0.2)";
            for (let sy = barY + barH + 5; sy < groundY - 5; sy += 9) {
                ctx.fillRect(-hw/2 + 1, sy, postW - 2, 4);
                ctx.fillRect(hw/2 - postW + 1, sy, postW - 2, 4);
            }

            // 기둥 하단 받침대
            ctx.fillStyle = "#c2410c";
            ctx.beginPath(); ctx.roundRect(-hw/2 - 3, groundY - 6, postW + 6, 6, 2); ctx.fill();
            ctx.beginPath(); ctx.roundRect(hw/2 - postW - 3, groundY - 6, postW + 6, 6, 2); ctx.fill();

            // 슬라이드 힌트 (아래 빈 공간에 화살표)
            ctx.fillStyle = "rgba(251,191,36,0.7)";
            ctx.font = "bold 9px sans-serif"; ctx.textAlign = "center"; ctx.textBaseline = "middle";
            ctx.fillText("↓", 0, (barY + groundY) / 2 + 3);

        } else {
            // 💣 둥근 폭탄: 점프로만 통과
            const r = 11; // 반지름 (원래 22px의 절반)

            // 그림자
            ctx.fillStyle = "rgba(0,0,0,0.4)";
            ctx.beginPath(); ctx.ellipse(3, r*0.8, r*0.85, r*0.35, 0, 0, Math.PI*2); ctx.fill();

            // 폭탄 본체 구체 (광택 그라디언트)
            const bombGrd = ctx.createRadialGradient(-r*0.3, -r*0.35, r*0.05, 0, 0, r);
            bombGrd.addColorStop(0, "#6b7280");
            bombGrd.addColorStop(0.35, "#374151");
            bombGrd.addColorStop(0.75, "#1f2937");
            bombGrd.addColorStop(1, "#111827");
            ctx.fillStyle = bombGrd;
            ctx.beginPath(); ctx.arc(0, 0, r, 0, Math.PI*2); ctx.fill();

            // 광택 하이라이트 (상단 왼쪽)
            const hlGrd = ctx.createRadialGradient(-r*0.32, -r*0.38, 0, -r*0.32, -r*0.38, r*0.55);
            hlGrd.addColorStop(0, "rgba(255,255,255,0.45)");
            hlGrd.addColorStop(1, "rgba(255,255,255,0)");
            ctx.fillStyle = hlGrd;
            ctx.beginPath(); ctx.arc(0, 0, r, 0, Math.PI*2); ctx.fill();

            // 심지 연결 꼭지 (상단 금속 링)
            ctx.fillStyle = "#6b7280";
            ctx.beginPath(); ctx.ellipse(0, -r+1, 3.5, 2.5, 0, 0, Math.PI*2); ctx.fill();
            ctx.strokeStyle = "#9ca3af"; ctx.lineWidth = 0.8;
            ctx.beginPath(); ctx.ellipse(0, -r+1, 3.5, 2.5, 0, 0, Math.PI*2); ctx.stroke();

            // 심지 (구불구불)
            ctx.strokeStyle = "#92400e"; ctx.lineWidth = 1.8; ctx.lineCap = "round";
            ctx.beginPath();
            ctx.moveTo(0, -r-1);
            ctx.bezierCurveTo(4, -r-6, -3, -r-10, 1, -r-16);
            ctx.stroke();

            // 심지 불꽃 (깜빡임)
            const flicker = 0.65 + Math.sin(frame * 0.4) * 0.35;
            ctx.save();
            ctx.globalAlpha = flicker;
            ctx.shadowBlur = 7; ctx.shadowColor = "#f97316";
            ctx.fillStyle = "#fbbf24";
            ctx.beginPath(); ctx.ellipse(1, -r-18, 2.8, 4, 0.15, 0, Math.PI*2); ctx.fill();
            ctx.fillStyle = "#fff7ed";
            ctx.beginPath(); ctx.ellipse(1, -r-19, 1.4, 2.2, 0.1, 0, Math.PI*2); ctx.fill();
            ctx.shadowBlur = 0;
            ctx.restore();

            // 점프 힌트
            ctx.fillStyle = "rgba(251,191,36,0.9)";
            ctx.font = "bold 8px sans-serif"; ctx.textAlign = "center"; ctx.textBaseline = "middle";
            ctx.fillText("↑JUMP", 0, -r - 26);
        }
        ctx.restore();
    });
}

function renderItemsR() {
    items.forEach(e => {
        ctx.save(); ctx.translate(e.x, e.y);
        const sz=e.size; const col = e.golden ? "#fbbf24" : e.item.color;

        if (e.golden) {
            // 골든 아이템: 회전 + 발광 + 별 모양 오라
            ctx.rotate(frame * 0.06);
            ctx.shadowBlur = 22; ctx.shadowColor = "#fbbf24";
            // 별 오라
            ctx.strokeStyle = "#fef08a"; ctx.lineWidth = 1.5; ctx.globalAlpha = 0.6 + Math.sin(frame*0.2)*0.4;
            ctx.beginPath();
            for (let s=0;s<5;s++) {
                const a = (s*4*Math.PI/5) - Math.PI/2;
                const ai = a + 2*Math.PI/5;
                s===0 ? ctx.moveTo(Math.cos(a)*(sz*0.75), Math.sin(a)*(sz*0.75)) : ctx.lineTo(Math.cos(a)*(sz*0.75), Math.sin(a)*(sz*0.75));
                ctx.lineTo(Math.cos(ai)*(sz*0.4), Math.sin(ai)*(sz*0.4));
            }
            ctx.closePath(); ctx.stroke();
            ctx.globalAlpha = 1;
        }

        ctx.shadowBlur = e.golden ? 20 : 14; ctx.shadowColor = col;
        ctx.fillStyle = col; ctx.fillRect(-sz/2,-sz/2,sz,sz);
        ctx.globalAlpha=0.8; ctx.fillStyle="#fff";
        ctx.fillRect(-sz/6,-sz/2,sz/3,sz); ctx.fillRect(-sz/2,-sz/6,sz,sz/3);
        ctx.globalAlpha=1;
        ctx.shadowBlur=0;
        ctx.fillStyle = e.golden ? "#78350f" : "#111827";
        ctx.fillRect(-sz*.44,-sz*.22,sz*.88,sz*.44);
        ctx.fillStyle = e.golden ? "#fef9c3" : "#fff";
        ctx.font="900 11px 'Noto Sans KR',sans-serif";
        ctx.textAlign="center"; ctx.textBaseline="middle";
        ctx.fillText(e.golden ? "★" : e.item.initial, 0, 1);
        ctx.restore();
    });
}

function renderParticlesR() {
    particles.forEach(p => {
        ctx.globalAlpha = p.life/20;
        ctx.fillStyle = p.color;
        ctx.beginPath(); ctx.arc(p.x,p.y,p.size,0,Math.PI*2); ctx.fill();
    });
    ctx.globalAlpha=1;
}

// ============================================================
// TOAST
// ============================================================
let toastTmr;
function showToast(item) {
    const tw = document.getElementById("toast-wrap");
    const ti = document.getElementById("toast-icon");
    document.getElementById("toast-title").textContent = "[" + item.name + "] 수집!";
    document.getElementById("toast-msg").textContent = item.desc;
    ti.innerHTML = `<svg viewBox="0 0 40 40" class="w-7 h-7"><rect x="5" y="15" width="30" height="22" rx="4" fill="${item.color}"/><rect x="3" y="10" width="34" height="6" rx="2" fill="${item.color}"/><rect x="17" y="10" width="6" height="27" fill="#fff" opacity="0.8"/><rect x="3" y="21" width="34" height="4" fill="#fff" opacity="0.8"/><rect x="7" y="24" width="26" height="10" fill="#111827" rx="1.5"/><text x="20" y="32" fill="#fff" font-size="7.5" font-family="Noto Sans KR" font-weight="900" text-anchor="middle">${item.initial}</text></svg>`;
    tw.style.opacity="1"; tw.style.transform="translateY(0)";
    clearTimeout(toastTmr);
    toastTmr = setTimeout(() => { tw.style.opacity="0"; tw.style.transform="translateY(-8px)"; }, 2800);
}

// ============================================================
// GAME OVER
// ============================================================
function endGame() {
    isPlaying = false;
    stopBGM();
    if (rafId) { cancelAnimationFrame(rafId); rafId = null; }

    let rank="C", comment="상생의 씨앗을 뿌려준 당신!", border="border-slate-500";
    const rs = Math.round(accumulatedScore + gameScore);
    if (rs >= 25000) { rank="S"; comment="조폐공사를 빛내는 '상생의 마에스트로'!"; border="border-emerald-500/80"; }
    else if (rs >= 12000) { rank="A"; comment="공공구매의 수호자!"; border="border-blue-500/80"; }
    else if (rs >= 5000) { rank="B"; comment="멋진 발걸음! 더 전진해 보세요!"; border="border-amber-500/80"; }

    document.getElementById("rank-ring").className = "w-24 h-24 flex items-center justify-center rounded-full bg-slate-900 border-4 " + border + " shadow-2xl";
    document.getElementById("result-rank").textContent = rank;
    document.getElementById("result-score").textContent = rs.toLocaleString() + " SVP";
    document.getElementById("result-uniques").textContent = uniqueCollected.size + " / 12 종";
    document.getElementById("result-total").textContent = totalCollected + " 개";
    document.getElementById("result-money").textContent = "₩ " + (rs * 1320).toLocaleString() + " 원";
    document.getElementById("result-carbon").textContent = (uniqueCollected.size * 1.35).toFixed(1) + "kg 감축";

    // 배틀 결과
    if (battleOpponentData) {
        const won = rs > battleOpponentData.score;
        const diff = Math.abs(rs - battleOpponentData.score);
        comment = won
            ? `🏆 승리! ${battleOpponentData.name}(${battleOpponentData.score.toLocaleString()})보다 ${diff.toLocaleString()} SVP 앞섰어요!`
            : rs === battleOpponentData.score
            ? `🤝 무승부! ${battleOpponentData.name}와 동점입니다!`
            : `😤 아쉽게 패배! ${battleOpponentData.name}(${battleOpponentData.score.toLocaleString()})보다 ${diff.toLocaleString()} SVP 부족!`;
        if (won) border = "border-amber-400";
        document.getElementById("rank-ring").className = "w-24 h-24 flex items-center justify-center rounded-full bg-slate-900 border-4 " + border + " shadow-2xl";
    }
    document.getElementById("rank-comment").textContent = comment;

    // PB 저장
    const finalScore = Math.round(accumulatedScore + gameScore);
    if (finalScore > personalBest) {
        personalBest = finalScore;
    }
    document.getElementById("pb-result-row").classList.remove("hidden");
    document.getElementById("pb-result-score").textContent = personalBest.toLocaleString() + " SVP";

    // 미션 결과 표시
    if (todayMissions.length) {
        document.getElementById("mission-result").classList.remove("hidden");
        document.getElementById("mission-result-list").innerHTML = todayMissions.map(m =>
            `<div class="flex justify-between items-center ${m.done ? "text-emerald-400" : "text-slate-500"}">
                <span>${m.done ? "✅" : "⬜"} ${m.desc}</span>
                <span class="font-bold">${m.done ? "+" + m.bonus + " SVP" : "미완료"}</span>
            </div>`
        ).join("");
    }

    document.getElementById("reg-container").classList.remove("hidden");
    showScreen("gameover");
}

async function submitScore() {
    const name = (document.getElementById("input-name").value || "조조달").trim();
    const dept = document.getElementById("select-dept").value;
    saveUserSettingsCache();
    const finalScore = Math.round(accumulatedScore + gameScore);
    RANKINGS.push({name, dept, score: finalScore, date: new Date().toISOString().split("T")[0]});
    const d = DEPT_STATS.find(x => x.name === dept);
    if (d) { d.total += finalScore; d.members++; }
    await saveScoreData({rankings: RANKINGS, deptStats: DEPT_STATS});
    document.getElementById("reg-container").classList.add("hidden");
    playSound("skill");
    showScreen("leaderboard");
}

// ============================================================
// LEADERBOARD
// ============================================================
let currentTab = "individual";
function changeTab(id) {
    currentTab = id;
    const ti = document.getElementById("tab-indiv"), td = document.getElementById("tab-dept");
    const ri = document.getElementById("ranking-indiv"), rd = document.getElementById("ranking-dept");
    if (id === "individual") {
        ti.className="w-1/2 py-2 text-xs font-black border-b-2 border-sky-500 text-sky-400";
        td.className="w-1/2 py-2 text-xs font-bold border-b-2 border-transparent text-slate-400";
        ri.classList.remove("hidden"); rd.classList.add("hidden"); renderRankings();
    } else {
        ti.className="w-1/2 py-2 text-xs font-bold border-b-2 border-transparent text-slate-400";
        td.className="w-1/2 py-2 text-xs font-black border-b-2 border-sky-500 text-sky-400";
        ri.classList.add("hidden"); rd.classList.remove("hidden"); renderDepts();
    }
}

function renderRankings() {
    const c = document.getElementById("ranking-indiv");
    const sorted = [...RANKINGS].sort((a,b)=>b.score-a.score);
    if (sorted.length === 0) {
        c.innerHTML = `<div class="text-center py-10 text-slate-500 text-xs">아직 등록된 점수가 없습니다.<br>첫 번째 기록을 남겨보세요! 🏃</div>`;
        return;
    }
    c.innerHTML = sorted.map((r,i) => {
        const medals = ["🥇","🥈","🥉"];
        const badge = i < 3 ? medals[i] : `<span class="text-xs text-slate-500">${i+1}위</span>`;
        const glow = i===0?"bg-sky-500/10 border-sky-500/30":i===1?"bg-slate-300/10 border-slate-300/30":i===2?"bg-amber-700/10 border-amber-700/30":"bg-slate-900 border-slate-800";
        return `<div class="p-3 border rounded-xl flex justify-between items-center ${glow}">
            <div class="flex items-center gap-3">
                <div class="w-8 h-8 flex items-center justify-center rounded-full bg-slate-950 font-black">${badge}</div>
                <div><span class="text-xs font-bold text-slate-200 block">${r.name} (${r.dept})</span><span class="text-[9px] text-slate-500">${r.date}</span></div>
            </div>
            <div class="text-right"><span class="text-xs font-extrabold retro-title text-white">${r.score.toLocaleString()}</span><span class="text-[9px] text-sky-400 block">SVP</span></div>
        </div>`;
    }).join("");
}

function renderDepts() {
    const c = document.getElementById("ranking-dept");
    const sorted = [...DEPT_STATS].sort((a,b)=>b.total-a.total);
    const maxVal = sorted[0].total;
    const barColors = ["bg-amber-500","bg-slate-400","bg-amber-700","bg-sky-500","bg-sky-500"];
    const textColors = ["text-amber-400","text-slate-300","text-amber-600","text-sky-400","text-sky-400"];
    c.innerHTML = sorted.map((d,i) => `
        <div class="bg-slate-900/60 border border-slate-800/80 p-3 rounded-2xl">
            <div class="flex justify-between items-center mb-1.5 text-xs">
                <span class="font-bold text-slate-200">${i+1}위. ${d.name} <span class="text-[10px] text-slate-500">(${d.members}명)</span></span>
                <span class="font-extrabold ${textColors[i]} retro-title">${d.total.toLocaleString()} SVP</span>
            </div>
            <div class="w-full h-2.5 bg-slate-950 rounded-full overflow-hidden">
                <div class="h-full ${barColors[i]} rounded-full" style="width:${Math.round(d.total/maxVal*100)}%"></div>
            </div>
        </div>`).join("");
}

// ============================================================
// ENCYCLOPEDIA
// ============================================================
function renderEncyclopedia() {
    document.getElementById("encyc-grid").innerHTML = PUBLIC_PURCHASES.map(item => `
        <button onclick="openModal(${item.id})" class="touch-manipulation flex flex-col p-3 bg-[#051126] border border-sky-950 hover:border-sky-700 rounded-2xl text-left active:scale-[0.98] transition-all">
            <div class="w-10 h-10 bg-slate-950 rounded-xl flex items-center justify-center mb-2 border border-slate-800">
                <svg viewBox="0 0 40 40" class="w-8 h-8"><rect x="5" y="15" width="30" height="22" rx="4" fill="${item.color}"/><rect x="3" y="10" width="34" height="6" rx="2" fill="${item.color}"/><rect x="17" y="10" width="6" height="27" fill="#fff" opacity="0.8"/><rect x="3" y="21" width="34" height="4" fill="#fff" opacity="0.8"/><rect x="7" y="24" width="26" height="10" fill="#111827" rx="1.5"/><text x="20" y="32" fill="#fff" font-size="7.5" font-family="Noto Sans KR" font-weight="900" text-anchor="middle">${item.initial}</text></svg>
            </div>
            <h4 class="text-xs font-black text-white leading-tight">${item.name}</h4>
            <span class="text-[9px] text-slate-400 mt-1 leading-relaxed line-clamp-2">${item.desc}</span>
        </button>`).join("");
}

function openModal(id) {
    const item = PUBLIC_PURCHASES.find(p=>p.id===id);
    if (!item) return;
    document.getElementById("modal-icon").innerHTML = `<svg viewBox="0 0 40 40" class="w-10 h-10"><rect x="5" y="15" width="30" height="22" rx="4" fill="${item.color}"/><rect x="3" y="10" width="34" height="6" rx="2" fill="${item.color}"/><rect x="17" y="10" width="6" height="27" fill="#fff" opacity="0.8"/><rect x="3" y="21" width="34" height="4" fill="#fff" opacity="0.8"/><rect x="7" y="24" width="26" height="10" fill="#111827" rx="1.5"/><text x="20" y="32" fill="#fff" font-size="7.5" font-family="Noto Sans KR" font-weight="900" text-anchor="middle">${item.initial}</text></svg>`;
    document.getElementById("modal-title").textContent = item.name;
    document.getElementById("modal-desc").textContent = item.desc;
    document.getElementById("modal-guide").textContent = item.guide;
    document.getElementById("modal").classList.remove("hidden");
}
function closeModal() { document.getElementById("modal").classList.add("hidden"); }

// ============================================================
// SHARE & BATTLE SYSTEM
// ============================================================
let shareMode = "game"; // "game" | "battle"
let pendingBattleRoomId = null;
let battleOpponentData = null;

function openShareModal(mode) {
    shareMode = mode;
    const modal = document.getElementById("share-modal");
    const badge = document.getElementById("share-modal-badge");
    const title = document.getElementById("share-modal-title");
    const sub = document.getElementById("share-modal-sub");
    const battleScore = document.getElementById("share-battle-score");
    const copyMsg = document.getElementById("share-copy-msg");

    copyMsg.classList.add("hidden");

    if (mode === "battle") {
        badge.textContent = "⚔️ 배틀 초대";
        badge.className = "text-[9px] bg-rose-500/10 border border-rose-500/20 text-rose-400 px-2 py-0.5 rounded-full font-bold";
        title.textContent = "내 점수로 배틀 초대";
        sub.textContent = "친구에게 배틀 링크를 보내 도전받으세요!";

        const score = Math.round(accumulatedScore + gameScore);
        const name = (document.getElementById("input-name").value || "조조달").trim();
        const dept = document.getElementById("select-dept").value;

        battleScore.classList.remove("hidden");
        document.getElementById("share-score-display").textContent = score.toLocaleString() + " SVP";
        document.getElementById("share-name-display").textContent = name + " (" + dept + ")";

        // 배틀 룸 ID 생성 & JSONBin에 저장
        pendingBattleRoomId = "battle_" + Date.now() + "_" + Math.random().toString(36).slice(2,7);
        saveBattleScore(pendingBattleRoomId, { name, dept, score, date: new Date().toISOString().split("T")[0] });
    } else {
        badge.textContent = "📣 게임 공유";
        badge.className = "text-[9px] bg-sky-500/10 border border-sky-500/20 text-sky-400 px-2 py-0.5 rounded-full font-bold";
        title.textContent = "게임 알리기";
        sub.textContent = "조폐공사 공공구매 게임을 소개해 보세요!";
        battleScore.classList.add("hidden");
        pendingBattleRoomId = null;
    }
    modal.classList.remove("hidden");
}

function closeShareModal() {
    document.getElementById("share-modal").classList.add("hidden");
}

function getBattleUrl() {
    const base = window.location.href.split("?")[0];
    if (pendingBattleRoomId) return base + "?battle=" + pendingBattleRoomId;
    return base;
}

function getShareText() {
    if (shareMode === "battle") {
        const score = Math.round(accumulatedScore + gameScore);
        const name = (document.getElementById("input-name").value || "조조달").trim();
        return `⚔️ [조팸스 런 배틀] ${name}이(가) ${score.toLocaleString()} SVP 점수로 도전장을 보냈습니다! 당신은 이길 수 있나요?`;
    }
    return "🏃 [조팸스 런: 공공구매 대작전] 조폐공사 공공구매 의식 고취 게임! 전국 거점을 달리며 아이템을 수집하세요! 🎮";
}

function doShare(method) {
    const url = getBattleUrl();
    const text = getShareText();
    const fullMsg = text + "\n" + url;

    if (method === "sms") {
        window.location.href = "sms:?body=" + encodeURIComponent(fullMsg);
    } else if (method === "kakao") {
        // 카카오링크 SDK가 없으므로 카카오톡 앱 공유 (모바일) 또는 링크 복사
        if (navigator.share) {
            navigator.share({ title: "조팸스 런!", text, url }).catch(()=>{});
        } else {
            window.open("https://story.kakao.com/share?url=" + encodeURIComponent(url), "_blank");
        }
    } else if (method === "email") {
        const subject = shareMode === "battle" ? "⚔️ 조팸스 런 배틀 도전!" : "🎮 조팸스 런 게임 추천!";
        window.location.href = "mailto:?subject=" + encodeURIComponent(subject) + "&body=" + encodeURIComponent(fullMsg);
    } else if (method === "twitter") {
        window.open("https://twitter.com/intent/tweet?text=" + encodeURIComponent(text) + "&url=" + encodeURIComponent(url), "_blank");
    } else if (method === "line") {
        window.open("https://social-plugins.line.me/lineit/share?url=" + encodeURIComponent(url) + "&text=" + encodeURIComponent(text), "_blank");
    } else if (method === "copy") {
        navigator.clipboard.writeText(fullMsg).then(() => {
            const msg = document.getElementById("share-copy-msg");
            msg.classList.remove("hidden");
            setTimeout(() => msg.classList.add("hidden"), 2500);
        }).catch(() => {
            // fallback
            const ta = document.createElement("textarea");
            ta.value = fullMsg; document.body.appendChild(ta); ta.select();
            document.execCommand("copy"); document.body.removeChild(ta);
            const msg = document.getElementById("share-copy-msg");
            msg.classList.remove("hidden");
            setTimeout(() => msg.classList.add("hidden"), 2500);
        });
    }
}

// ── 배틀 점수 JSONBin 저장 ──
async function saveBattleScore(roomId, data) {
    try {
        const existing = await loadScoreData();
        if (!existing.battles) existing.battles = {};
        existing.battles[roomId] = data;
        await saveScoreData(existing);
    } catch(e) { console.warn("배틀 저장 실패:", e); }
}

// ── 배틀 점수 불러오기 ──
async function loadBattleScore(roomId) {
    try {
        const data = await loadScoreData();
        return (data.battles && data.battles[roomId]) || null;
    } catch(e) { return null; }
}

// ── URL 파라미터 체크 → 배틀 배너 표시 ──
(async function checkBattleParam() {
    const params = new URLSearchParams(window.location.search);
    const roomId = params.get("battle");
    if (!roomId) return;
    const opp = await loadBattleScore(roomId);
    if (!opp) return;
    battleOpponentData = opp;
    const banner = document.getElementById("battle-banner");
    document.getElementById("battle-banner-text").textContent = `${opp.name} (${opp.dept})의 도전을 받았습니다!`;
    document.getElementById("battle-opponent-score").textContent = `도전 점수: ${opp.score.toLocaleString()} SVP — 이 점수를 넘겨라!`;
    banner.classList.remove("hidden");
    // 게임 오버 시 배틀 결과 표시를 위해 HUD에도 반영
})();

// ============================================================
// INIT
// ============================================================
applyUserSettingsCache();
bindUserSettingsCacheEvents();
showScreen("menu");
